function resolveDocumentedFlows(flows: DocumentedFlow[], graph: ArchitectureGraph): Array<{ from: string; to: string }> {
  const find = (label:string) => graph.nodes.find((node) => { const value=label.toLowerCase().replace(/[^a-z0-9]/g,''); const path=node.path.toLowerCase().replace(/[^a-z0-9]/g,''); const name=node.name.toLowerCase().replace(/[^a-z0-9]/g,''); return value.length>2&&(path.includes(value)||name.includes(value)||value.includes(name)) })
  return flows.flatMap((flow)=>{const from=find(flow.source),to=find(flow.target);return from&&to&&from.id!==to.id?[{from:from.id,to:to.id}]:[]})
}
function resolveMapperFlows(artifact: MapperFlowArtifact, graph: ArchitectureGraph): Array<{ from: string; to: string }> {
  const find = (label:string) => graph.nodes.find((node) => node.id===label || node.path===label || node.name.toLowerCase()===label.toLowerCase() || node.path.toLowerCase().includes(label.toLowerCase()))
  return artifact.edges.flatMap((edge)=>{const from=find(edge.from),to=find(edge.to);return from&&to&&from.id!==to.id?[{from:from.id,to:to.id}]:[]})
}
