function renderPalette(query = '') { paletteResults.innerHTML = ''; searchCommands(paletteCommands, query).forEach((command) => { const item = document.createElement('button'); item.className = 'command-result'; item.innerHTML = `${escapeHtml(command.label)}<small>${escapeHtml(command.category)}${command.keybinding ? ` · ${escapeHtml(command.keybinding)}` : ''}</small>`; item.addEventListener('click', async () => { palette.hidden = true; await command.run() }); paletteResults.append(item) }) }
function openPalette() { palette.hidden = false; paletteInput.value = ''; renderPalette(); paletteInput.focus() }
paletteInput.addEventListener('input', () => renderPalette(paletteInput.value)); palette.addEventListener('click', (event) => { if (event.target === palette) palette.hidden = true }); addEventListener('keydown', (event) => { if ((event.ctrlKey || event.metaKey) && (event.key.toLowerCase() === 'k' || event.key.toLowerCase() === 'p')) { event.preventDefault(); openPalette() } if (event.key === 'Escape' && !palette.hidden) palette.hidden = true }); renderPalette()
function bindExplorerSearch() {
  const input = activityContent.querySelector<HTMLInputElement>('input[placeholder="Search files and symbols"]')
  if (!input || input.dataset.bound) return
  input.dataset.bound = 'true'
  input.addEventListener('input', () => {
    const query = input.value.trim().toLowerCase()
    const visible = new Set<string>()
    meshNodes.forEach((node, mesh) => {
      const match = !query || `${node.name} ${node.path} ${node.layer} ${node.kind}`.toLowerCase().includes(query)
      mesh.visible = match
      nodeSprites.get(mesh)!.visible = match
      if (match) visible.add(node.id)
    })
    group.children.forEach((child) => {
      if (child instanceof THREE.Mesh && child.userData.from && child.userData.to) child.visible = visible.has(child.userData.from) && visible.has(child.userData.to)
    })
    const count = visible.size
    input.setAttribute('aria-label', `${count} matching mapped objects`)
    focusVisibleNodes()
  })
}
function focusVisibleNodes() {
  const points = [...meshNodes.entries()].filter(([mesh]) => mesh.visible).map(([mesh]) => ({ x: mesh.position.x, z: mesh.position.z }))
  if (!points.length) return
  const frame = focusFrame(points); controls.target.set(frame.x, 0, frame.z); camera.position.set(frame.x + frame.span * .55, Math.max(14, frame.span * .9), frame.z + frame.span * .75); camera.lookAt(controls.target); controls.update()
}
document.querySelectorAll<HTMLButtonElement>('[data-activity]').forEach((button) => button.addEventListener('click', () => setTimeout(bindExplorerSearch, 0)))
function escapeHtml(value:string){return value.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}
function showEdgeProposal(edge: ArchitectureEdge) { const proposal = latestGraph ? proposeEdgeReversal(latestGraph, edge) : undefined; const errors = proposal?.errors.length ? `<p class="error">${proposal.errors.join('; ')}</p>` : '<p class="ok">reversão validada contra ciclos e duplicatas</p>'; document.querySelector('#inspector')!.classList.add('open'); document.querySelector('#selection')!.innerHTML = `<p class="eyebrow">REFATORAÇÃO VISUAL · PREVIEW</p><h2>Reverter conexão</h2><code>${edge.from} → ${edge.to}</code>${errors}<dl><dt>OPERAÇÕES</dt><dd>${proposal?.operations.length ?? 0}</dd><dt>APLICAR</dt><dd>bloqueado no preview</dd></dl><p class="subhead">A proposta é somente leitura; a aplicação exige trust, diff, checkpoint e confirmação APPLY no host.</p>` }
function showNode(node:ArchitectureNode){const file=analysis?.files.find(item=>item.path===node.path);if(file){editorState=openEditorFile(editorState,{path:file.path,content:file.content,language:file.language});}const incoming=analysis?.connections.filter(item=>item.target===node.path&&!item.external)??[];const imports=file?.imports??[];const flows=file?.path.match(/readme/i)?analysis?.documentedFlows??[]:[];const mode=file?editorMode(file.path,new Set(writableHandles.keys())):'download-only';document.querySelector('#inspector')!.classList.add('open');document.querySelector('#selection')!.innerHTML=`<div class="piece-icon" style="--c:${LAYERS[node.layer].color}">⊕</div><p class="tag">${node.layer} / ${node.kind}${file?` / ${file.language}`:''}</p><h2>${node.name}</h2><code>${node.path}</code>${file?`<div class="editor-tabs-local" role="tablist">${editorState.tabs.map((tab)=>`<button class="${tab.id===editorState.activeId?'active':''}" data-editor-tab="${escapeHtml(tab.path)}" role="tab">${escapeHtml(tab.path.split('/').pop()??tab.path)}${tab.dirty?' •':''}</button>`).join('')}</div><dl><dt>LINHAS</dt><dd>${file.lines}</dd><dt>IMPORTS</dt><dd>${imports.length}</dd><dt>IMPORTADO POR</dt><dd>${incoming.length}</dd></dl><p class="subhead">TERMINAL · ${mode==='writable'?'EDITÁVEL':'EXPORTÁVEL'}</p><div class="code-terminal"><header><i></i><i></i><i></i><span>${file.language}</span></header><textarea id="source-editor" spellcheck="false">${escapeHtml(editorState.tabs.find((tab)=>tab.path===file.path)?.content??file.content)}</textarea></div><div class="editor-actions"><button id="save-source">${mode==='writable'?'SALVAR NO PROJETO':'BAIXAR ARQUIVO ALTERADO'}</button><small>${mode==='writable'?'gravação local autorizada':'importe pelo botão Abrir projeto para salvar no disco'}</small></div>${flows.length?`<p class="subhead">FLUXOS DOCUMENTADOS</p><div class="imports documented">${flows.map(flow=>`<span>⇢ ${flow.source} <b>→</b> ${flow.target}</span>`).join('')}</div>`:''}<p class="subhead">DEPENDÊNCIAS</p><div class="imports">${imports.length?imports.map(item=>`<span class="${item.external?'external':''}">→ ${item.specifier}<small>${item.resolvedPath??'pacote externo'}</small></span>`).join(''):'<em>nenhuma detectada</em>'}</div>`:`<dl><dt>ENTRADA</dt><dd>${PIECES[node.kind].socket}</dd><dt>SAÍDA</dt><dd>${PIECES[node.kind].tab}</dd></dl>`}`
  const save=document.querySelector<HTMLButtonElement>('#save-source');if(file&&save)save.onclick=async()=>{const next=document.querySelector<HTMLTextAreaElement>('#source-editor')!.value;const handle=writableHandles.get(file.path);if(handle){const writable=await handle.createWritable();await writable.write(next);await writable.close();file.content=next;file.size=new Blob([next]).size;file.lines=next.split('\n').length;editorState=markEditorSaved(editorState,`file:${file.path}`,next);showNode(node);return}const anchor=document.createElement('a');anchor.href=URL.createObjectURL(new Blob([next],{type:'text/plain'}));anchor.download=file.path.split('/').pop()??file.path;anchor.click();URL.revokeObjectURL(anchor.href)};const editor=document.querySelector<HTMLTextAreaElement>('#source-editor');if(file&&editor){editor.addEventListener('input',()=>{editorState=updateEditorContent(editorState,`file:${file.path}`,editor.value);const tab=document.querySelector<HTMLButtonElement>(`[data-editor-tab="${CSS.escape(file.path)}"]`);if(tab)tab.textContent=`${file.path.split('/').pop()??file.path} •`})};document.querySelectorAll<HTMLButtonElement>('[data-editor-tab]').forEach((tab)=>tab.addEventListener('click',()=>{const next=[...meshNodes.values()].find((item)=>item.path===tab.dataset.editorTab);if(next)showNode(next)}))
}
canvas.addEventListener('click',(e)=>{const rect=canvas.getBoundingClientRect();pointer.set((e.clientX-rect.left)/rect.width*2-1,-(e.clientY-rect.top)/rect.height*2+1);raycaster.setFromCamera(pointer,camera);const edgeHit=raycaster.intersectObjects([...edgeObjects.keys()])[0];if(edgeHit){const edge=edgeObjects.get(edgeHit.object);if(edge){showEdgeProposal(edge);return}}const hit=raycaster.intersectObjects([...clickableNodes.keys()])[0];if(hit)showNode(clickableNodes.get(hit.object)!)})
const help=document.querySelector<HTMLElement>('#help')!;const helpTrigger=document.querySelector<HTMLButtonElement>('#help-trigger')!;const applyHandMode=()=>{document.body.classList.toggle('hand-mode',handMode);helpTrigger.classList.toggle('active',handMode);helpTrigger.setAttribute('aria-pressed',String(handMode));helpTrigger.title=handMode?'Modo mão ativo · H ou Esc para sair':'Ativar modo mão · H';if(dragControls)dragControls.enabled=!handMode;if(handMode)help.hidden=false};const toggleHand=()=>{handMode=nextHandToolState(handMode,'h');applyHandMode()};helpTrigger.addEventListener('click',toggleHand);document.querySelector('#help-close')!.addEventListener('click',()=>{help.hidden=true});addEventListener('keydown',(event)=>{if((event.target instanceof HTMLInputElement||event.target instanceof HTMLTextAreaElement))return;if(event.key.toLowerCase()==='h'){toggleHand();return}if(event.key.toLowerCase()==='f'){focusVisibleNodes();return}if(event.key==='Escape'&&handMode){handMode=nextHandToolState(handMode,'escape');applyHandMode();help.hidden=true}});applyHandMode()
const viewToggle=document.querySelector<HTMLButtonElement>('#view-toggle')!;const applyCameraView=()=>{if(cameraView==='top'){perspectivePosition.copy(camera.position);perspectiveTarget.copy(controls.target);const box=new THREE.Box3().setFromObject(group);const center=box.getCenter(new THREE.Vector3());const size=box.getSize(new THREE.Vector3());controls.target.copy(center);camera.up.set(0,0,-1);camera.position.set(center.x,Math.max(32,Math.max(size.x,size.z)*1.35),center.z+.01);camera.lookAt(center);viewToggle.textContent='◇ 3D';viewToggle.classList.add('active')}else{camera.up.set(0,1,0);camera.position.copy(perspectivePosition.lengthSq()?perspectivePosition:new THREE.Vector3(18,18,29));controls.target.copy(perspectiveTarget.lengthSq()?perspectiveTarget:new THREE.Vector3(10,0,1));camera.lookAt(controls.target);viewToggle.textContent='⌗ TOP';viewToggle.classList.remove('active')}controls.update()};const toggleCameraView=()=>{cameraView=nextCameraView(cameraView);applyCameraView()};viewToggle.addEventListener('click',toggleCameraView);addEventListener('keydown',(event)=>{if(event.key.toLowerCase()==='t'&&!(event.target instanceof HTMLInputElement||event.target instanceof HTMLTextAreaElement))toggleCameraView()})
